import os
import numpy as np
from typing import List, Dict, Tuple
import json
import pickle
from pathlib import Path

class SimpleVectorDB:
    def __init__(self, embedding_dim: int = 384):
        self.embeddings = []
        self.documents = []
        self.metadata = []
        self.embedding_dim = embedding_dim
    
    def add_documents(self, texts: List[str], embeddings: np.ndarray, metadata: List[Dict] = None):
        self.documents.extend(texts)
        self.embeddings.append(embeddings)
        if metadata:
            self.metadata.extend(metadata)
        else:
            self.metadata.extend([{}] * len(texts))
    
    def search(self, query_embedding: np.ndarray, top_k: int = 5) -> List[Tuple[str, float, Dict]]:
        if len(self.embeddings) == 0:
            return []
        
        all_embeddings = np.vstack(self.embeddings)
        
        query_norm = np.linalg.norm(query_embedding)
        doc_norms = np.linalg.norm(all_embeddings, axis=1)
        
        similarities = np.dot(all_embeddings, query_embedding) / (doc_norms * query_norm + 1e-8)
        
        top_indices = np.argsort(similarities)[::-1][:top_k]
        
        results = []
        for idx in top_indices:
            results.append((self.documents[idx], float(similarities[idx]), self.metadata[idx]))
        
        return results
    
    def save(self, path: str):
        data = {
            'embeddings': self.embeddings,
            'documents': self.documents,
            'metadata': self.metadata,
            'embedding_dim': self.embedding_dim
        }
        with open(path, 'wb') as f:
            pickle.dump(data, f)
    
    def load(self, path: str):
        with open(path, 'rb') as f:
            data = pickle.load(f)
        self.embeddings = data['embeddings']
        self.documents = data['documents']
        self.metadata = data['metadata']
        self.embedding_dim = data['embedding_dim']


class SimpleEmbedder:
    def __init__(self):
        try:
            from sentence_transformers import SentenceTransformer
            self.model = SentenceTransformer('all-MiniLM-L6-v2')
            self.use_transformers = True
        except:
            self.use_transformers = False
            self.vocab = {}
            self.embedding_dim = 384
    
    def _simple_hash_embedding(self, text: str) -> np.ndarray:
        words = text.lower().split()
        embedding = np.zeros(self.embedding_dim)
        
        for word in words:
            hash_val = hash(word)
            for i in range(self.embedding_dim):
                embedding[i] += np.sin(hash_val * (i + 1) * 0.01)
        
        if len(words) > 0:
            embedding = embedding / len(words)
        
        norm = np.linalg.norm(embedding)
        if norm > 0:
            embedding = embedding / norm
        
        return embedding
    
    def embed(self, texts: List[str]) -> np.ndarray:
        if self.use_transformers:
            return self.model.encode(texts)
        else:
            return np.array([self._simple_hash_embedding(text) for text in texts])
    
    def embed_query(self, query: str) -> np.ndarray:
        if self.use_transformers:
            return self.model.encode([query])[0]
        else:
            return self._simple_hash_embedding(query)


class DocumentChunker:
    def __init__(self, chunk_size: int = 500, overlap: int = 50):
        self.chunk_size = chunk_size
        self.overlap = overlap
    
    def chunk_text(self, text: str, metadata: Dict = None) -> List[Tuple[str, Dict]]:
        words = text.split()
        chunks = []
        
        for i in range(0, len(words), self.chunk_size - self.overlap):
            chunk = ' '.join(words[i:i + self.chunk_size])
            chunk_metadata = metadata.copy() if metadata else {}
            chunk_metadata['chunk_index'] = len(chunks)
            chunks.append((chunk, chunk_metadata))
            
            if i + self.chunk_size >= len(words):
                break
        
        return chunks if chunks else [(text, metadata or {})]


class LLMInterface:
    def __init__(self, api_key: str = None, model: str = "gpt-3.5-turbo"):
        self.api_key = api_key or os.getenv("OPENAI_API_KEY")
        self.model = model
        self.use_api = self.api_key is not None
    
    def generate(self, prompt: str, max_tokens: int = 500) -> str:
        if self.use_api:
            try:
                import openai
                openai.api_key = self.api_key
                
                response = openai.ChatCompletion.create(
                    model=self.model,
                    messages=[{"role": "user", "content": prompt}],
                    max_tokens=max_tokens,
                    temperature=0.7
                )
                
                return response.choices[0].message.content
            except Exception as e:
                return f"LLM API Error: {str(e)}\n\n[Using fallback response]"
        else:
            return f"[Mock LLM Response - Configure API key for actual responses]\n\nBased on the provided context, here is a response to your query."


class RAGSystem:
    def __init__(self, chunk_size: int = 500, chunk_overlap: int = 50, db_path: str = "vector_db.pkl"):
        self.embedder = SimpleEmbedder()
        self.chunker = DocumentChunker(chunk_size=chunk_size, overlap=chunk_overlap)
        self.vector_db = SimpleVectorDB()
        self.llm = LLMInterface()
        self.db_path = db_path
    
    def load_documents_from_directory(self, directory: str):
        directory_path = Path(directory)
        
        for file_path in directory_path.rglob('*'):
            if file_path.is_file() and file_path.suffix in ['.txt', '.md', '.json']:
                try:
                    with open(file_path, 'r', encoding='utf-8') as f:
                        content = f.read()
                    
                    metadata = {
                        'source': str(file_path),
                        'filename': file_path.name,
                        'type': file_path.suffix
                    }
                    
                    self.add_document(content, metadata)
                except Exception as e:
                    print(f"Error loading {file_path}: {e}")
    
    def add_document(self, text: str, metadata: Dict = None):
        chunks = self.chunker.chunk_text(text, metadata)
        
        chunk_texts = [chunk[0] for chunk in chunks]
        chunk_metadata = [chunk[1] for chunk in chunks]
        
        embeddings = self.embedder.embed(chunk_texts)
        
        self.vector_db.add_documents(chunk_texts, embeddings, chunk_metadata)
    
    def add_documents(self, documents: List[Dict]):
        for doc in documents:
            text = doc.get('text', '')
            metadata = {k: v for k, v in doc.items() if k != 'text'}
            self.add_document(text, metadata)
    
    def query(self, question: str, top_k: int = 5, return_sources: bool = True) -> Dict:
        query_embedding = self.embedder.embed_query(question)
        
        retrieved_docs = self.vector_db.search(query_embedding, top_k=top_k)
        
        context = self._build_context(retrieved_docs)
        
        prompt = self._create_prompt(question, context)
        
        response = self.llm.generate(prompt)
        
        result = {
            'question': question,
            'answer': response,
            'sources': []
        }
        
        if return_sources:
            for doc, score, metadata in retrieved_docs:
                result['sources'].append({
                    'content': doc[:200] + '...' if len(doc) > 200 else doc,
                    'score': score,
                    'metadata': metadata
                })
        
        return result
    
    def _build_context(self, retrieved_docs: List[Tuple[str, float, Dict]]) -> str:
        context_parts = []
        
        for i, (doc, score, metadata) in enumerate(retrieved_docs, 1):
            source_info = metadata.get('source', 'Unknown')
            context_parts.append(f"Document {i} (from {source_info}):\n{doc}\n")
        
        return "\n".join(context_parts)
    
    def _create_prompt(self, question: str, context: str) -> str:
        prompt = f"""You are a helpful assistant for our company's internal knowledge base. 
Answer the question based on the context provided below. If the context doesn't contain 
relevant information, say so honestly.

Context:
{context}

Question: {question}

Answer:"""
        return prompt
    
    def save_database(self, path: str = None):
        save_path = path or self.db_path
        self.vector_db.save(save_path)
        print(f"Database saved to {save_path}")
    
    def load_database(self, path: str = None):
        load_path = path or self.db_path
        if os.path.exists(load_path):
            self.vector_db.load(load_path)
            print(f"Database loaded from {load_path}")
        else:
            print(f"No database found at {load_path}")


